def img_html_from_b64(b64_text: str, class_name: str = "habesha-logo") -> str:
    if not b64_text:
        return ""
    return f'<img class="{class_name}" src="data:image/png;base64,{b64_text}" />'

def clean_numeric(series: pd.Series) -> pd.Series:
    return pd.to_numeric(
        series.astype(str)
        .str.replace(",", "", regex=False)
        .str.replace("%", "", regex=False)
        .str.strip(),
        errors="coerce",
    ).fillna(0)

def canonicalize_columns(df: pd.DataFrame) -> pd.DataFrame:
    df = df.copy()
    df.columns = df.columns.astype(str).str.strip()

    rename_map = {
        "Beginning_Stock": "Beginning Stock",
        "MTD_Shipment": "MTD Shipment",
        "MTD_PY_Shipment": "MTD PY Shipment",
        "MTD_Depletion": "MTD Depletion",
        "Stock_Balance": "Stock Balance",
        "Avg_Daily_Depletion": "Avg Daily Depletion",
        "Days_of_Stock": "Days of Stock",
        "MTD_Landing": "MTD Landing",
        "YTD_Shipment": "YTD Shipment",
        "YTD_PY_Shipment": "YTD PY Shipment",
        "YTD_Depletion": "YTD Depletion",
        "Yearly_Landing": "Yearly Landing",
        "Avg_Daily_MTD_Shipment": "Avg Daily MTD Shipment",
        "Avg_Daily_YTD_Shipment": "Avg Daily YTD Shipment",
        "MTD_Target_AOP": "MTD Target AOP",
        "MTD_Target_SNOP": "MTD Target SNOP",
        "MTD_Target_Sales": "MTD Target Sales",
        "YTD_Target_AOP": "YTD Target AOP",
        "YTD_Target_SNOP": "YTD Target SNOP",
        "YTD_Target_Sales": "YTD Target Sales",
        "Full_Month_Target_AOP": "Full Month Target AOP",
        "Full_Month_Target_SNOP": "Full Month Target SNOP",
        "Full_Month_Target_Sales": "Full Month Target Sales",
        "Full_Year_Target_AOP": "Full Year Target AOP",
        "Full_Year_Target_SNOP": "Full Year Target SNOP",
        "Full_Year_Target_Sales": "Full Year Target Sales",
    }

    df = df.rename(columns={k: v for k, v in rename_map.items() if k in df.columns})

    if "DV" in df.columns and "Division" not in df.columns:
        df = df.rename(columns={"DV": "Division"})

    if "UOM" not in df.columns:
        df["UOM"] = "Crates"

    for col in ["Division", "Agent", "Brand"]:
        if col not in df.columns:
            df[col] = "Unknown"

    numeric_candidates = [
        "Beginning Stock", "MTD Shipment", "MTD PY Shipment", "MTD Depletion",
        "Stock Balance", "Avg Daily Depletion", "Days of Stock", "MTD Landing",
        "YTD Shipment", "YTD PY Shipment", "YTD Depletion", "Yearly Landing",
        "MTD Target AOP", "MTD Target SNOP", "MTD Target Sales",
        "YTD Target AOP", "YTD Target SNOP", "YTD Target Sales",
        "Full Month Target AOP", "Full Month Target SNOP", "Full Month Target Sales",
        "Full Year Target AOP", "Full Year Target SNOP", "Full Year Target Sales",
        "MTD Variance vs PY", "YTD Variance vs PY",
        "Avg Daily MTD Shipment", "Avg Daily YTD Shipment",
        "MTD Achievement vs PY %", "YTD Achievement vs PY %",
        "MTD Achievement vs AOP %", "MTD Achievement vs SNOP %", "MTD Achievement vs Sales %",
        "YTD Achievement vs AOP %", "YTD Achievement vs SNOP %", "YTD Achievement vs Sales %",
        "MTD Landing vs AOP %", "MTD Landing vs SNOP %", "MTD Landing vs Sales %",
        "Yearly Landing vs AOP %", "Yearly Landing vs SNOP %", "Yearly Landing vs Sales %",
    ]

    for col in numeric_candidates:
        if col in df.columns:
            df[col] = clean_numeric(df[col])

    return df

def safe_div(n, d):
    return 0 if d == 0 else n / d

def fmt_num(v):
    return f"{v:,.0f}"

def fmt_pct(v):
    return f"{v:.1%}"

def target_cols(target: str):
    return {
        "mtd": f"MTD Target {target}",
        "ytd": f"YTD Target {target}",
        "full_month": f"Full Month Target {target}",
        "full_year": f"Full Year Target {target}",
    }

def sum_col(df: pd.DataFrame, col: str) -> float:
    if col not in df.columns:
        return 0.0
    return float(df[col].sum())

def aggregate_for_chart(df: pd.DataFrame, group_col: str, metrics: list[str]) -> pd.DataFrame:
    available = [m for m in metrics if m in df.columns]
    if not available or group_col not in df.columns:
        return pd.DataFrame()
    return (
        df.groupby(group_col, dropna=False)[available]
        .sum()
        .reset_index()
        .sort_values(available[0], ascending=False)
    )

def download_csv(df: pd.DataFrame, filename: str):
    csv = df.to_csv(index=False).encode("utf-8-sig")
    st.download_button(
        label="Download filtered CSV",
        data=csv,
        file_name=filename,
        mime="text/csv",
        use_container_width=True,
    )

